import { writable } from 'svelte/store';
import { get } from 'js-cookie';
const initialState = {
    isNew: !!get('hasConfig')
};
const { subscribe, set } = writable(initialState);
const setIsNew = (isNew) => set(Object.assign(Object.assign({}, initialState), { isNew: isNew }));
export default {
    subscribe,
    setIsNew
};
